#include<iostream>#include<vector>using namespace std ;int max_occurrence(vector<int> s , int target){	//here we will use the brute force method to get the last target 	int max_occur = INT_MIN;	for(int index = 0 ; index < s.size() ; index++)	{		if(s[index] == target)		{			max_occur = max(max_occur , index);		}	}	return max_occur;}// now lets start with another optimized version of the algorithm // we know that the array is a sorted array int max_occurrence_optimized(vector<int> s , int target){	//if you find the target element in the mid , we can get a perspective answer  , but still we would need to traverse 	int answer = INT_MIN; // we would need to update only if the current element is greater than the max , that is wwe found a bigger index with the same target	int low = 0 ;	int high = s.size();	while(low<=high)	{		if(s[(low+high)/2] == target)		{			answer = max(answer , (low+high)/2);			// we then update to check the right hand side  , to get the max index 			low = (low+high)/2 + 1;		}		else if(s[(low+high)/2] > target)		{			// we then need to move to  the first half  of the array			high = (low+high)/2 -1;		}		else 		{			// the target is greater than the mid 			low = (low+high)/2+1 ;		}	}	// after getting the required  index  , we then return the required index 	return answer;}int main(){	// no{w lets write the code for the main programme 	vector<int> s1 {12 , 12 ,13 , 13 , 15 , 15 ,15 , 16 , 16 ,16 ,16};	int max_occur = max_occurrence(s1 , 15);	cout<<"THE MAX OCCURRENCE MATRIX IS GIVEN  BY "<< max_occur <<endl;	// now lets get the output of the model using the optimized model and then check whether we get the same answerfrom them or not 	int max_occur1 = max_occurrence_optimized(s1, 15);	cout<<"THE MAX OCCURRENCE INDEX OF THE TARGET IS GIVEN BY "<<max_occur1;}